mapper.select:
SELECT o.order_id AS orderId, u.user_id AS "userVo.userId", u.phone_number AS "userVo.phoneNumber", u.student_id AS "userVo.studentId", u.campus_card AS "userVo.campusCard", u.balance AS "userVo.balance", s.school_id AS "schoolsVo.schoolId", s.school_name AS "schoolsVo.schoolName", s.location AS "schoolsVo.location", l.locker_id AS "lockersVo.lockerId", l.locker_number AS "lockersVo.lockerNumber", l.status AS "lockersVo.lockerStatus", lp.item_id AS "laundryPackageVo.itemId", lp.item_name AS "laundryPackageVo.itemName", lp.base_price AS "laundryPackageVo.basePrice", lp.description AS "laundryPackageVo.description", o.order_no AS orderNo, o.total_price AS totalPrice, o.pay_price as payPrice, o.created_at AS createdAt, o.updated_at AS updatedAt, o.status AS status, o.pickup_code AS pickupCode
AND o.user_id = #{searchForm.userId}
AND u.phone_number = #{searchForm.phoneNumber}
AND s.school_name LIKE CONCAT('%', #{searchForm.schoolName}, '%')
AND o.order_no LIKE CONCAT('%', #{searchForm.orderNo}, '%')
AND o.laundry_items_id = #{searchForm.laundryItemsId}
AND o.created_at >= #{searchForm.startTime}
AND o.created_at <= #{searchForm.endTime}
AND o.status = #{searchForm.status}

SELECT o.order_id AS orderId, s.school_id AS "schoolsVo.schoolId", s.school_name AS "schoolsVo.schoolName", s.location AS "schoolsVo.location", l.locker_id AS "lockersVo.lockerId", l.locker_number AS "lockersVo.lockerNumber", l.status AS "lockersVo.lockerStatus", lp.item_id AS "laundryPackageVo.itemId", lp.item_name AS "laundryPackageVo.itemName", lp.base_price AS "laundryPackageVo.basePrice", o.order_no AS orderNo, o.total_price AS totalPrice, o.pay_price as payPrice, o.created_at AS createdAt, o.updated_at AS updatedAt, o.status AS status, o.pickup_code AS pickupCode FROM orders o JOIN schools s ON o.school_id = s.school_id LEFT JOIN lockers l ON o.locker_id = l.locker_id LEFT JOIN laundry_items lp ON o.laundry_items_id = lp.item_id where user_id = #{userId}
and o.status = #{status}
order by updated_at desc
